from django.http import HttpRequest, HttpResponse
from django.shortcuts import render


def index(request: HttpRequest) -> HttpResponse:
    return render(request, "chat/index.html")

from django.template.loader import render_to_string


def test_base_template_renders() -> None:
    html = render_to_string("base.html")
    assert "<!DOCTYPE html>" in html
    assert "Ollama Chat" in html
    assert 'src="/static/js/chat.js"' in html


def test_index_template_extends_base() -> None:
    html = render_to_string("chat/index.html")
    assert "chat-messages" in html
    assert "message-input" in html


def test_message_partial_user() -> None:
    html = render_to_string(
        "chat/includes/message.html", {"role": "user", "content": "hello"}
    )
    assert "items-end" in html
    assert "hello" in html
    assert "bg-gray-700" in html


def test_message_partial_assistant() -> None:
    html = render_to_string(
        "chat/includes/message.html", {"role": "assistant", "content": "hi there"}
    )
    assert "items-start" in html
    assert "hi there" in html
    assert "bg-gray-800" in html


def test_chat_input_renders() -> None:
    html = render_to_string("chat/includes/chat_input.html")
    assert "chat-form" in html
    assert "message-input" in html
    assert "send-button" in html

