{% extends "base.html" %}

{% block content %}
<div id="chat-messages" class="flex-1 overflow-y-auto py-4 space-y-4">
    <div class="text-center text-gray-500 mt-8">
        Send a message to start chatting with the model.
    </div>
</div>

{% include "chat/includes/chat_input.html" %}
{% endblock %}

(function () {
    const messages = document.getElementById("chat-messages");
    const form = document.getElementById("chat-form");
    const input = document.getElementById("message-input");
    const sendBtn = document.getElementById("send-button");

    let ws = null;
    let currentAssistantDiv = null;
    let currentContentEl = null;

    function connect() {
        const protocol = window.location.protocol === "https:" ? "wss" : "ws";
        ws = new WebSocket(protocol + "://" + window.location.host + "/ws/chat/");

        ws.onmessage = function (event) {
            const data = JSON.parse(event.data);

            if (data.type === "start") {
                appendAssistantBubble();
            } else if (data.type === "token") {
                if (currentContentEl) {
                    currentContentEl.textContent += data.content;
                    messages.scrollTop = messages.scrollHeight;
                }
            } else if (data.type === "end") {
                resetAssistantState();
                enableInput();
            } else if (data.type === "error") {
                if (currentContentEl) {
                    currentContentEl.textContent += "\n\nError: " + data.content;
                    currentContentEl.classList.add("text-red-400");
                } else {
                    appendError(data.content);
                }
                resetAssistantState();
                enableInput();
            }
        };

        ws.onclose = function () {
            if (currentAssistantDiv) {
                resetAssistantState();
                enableInput();
            }
            setTimeout(connect, 1000);
        };

        ws.onerror = function () {
            ws.close();
        };
    }

    function appendUserBubble(text) {
        const div = document.createElement("div");
        div.className = "flex flex-col items-end";
        div.innerHTML =
            '<div class="max-w-[80%] rounded-lg px-4 py-3 bg-gray-700 text-gray-200"><p class="whitespace-pre-wrap"></p></div>';
        div.querySelector("p").textContent = text;
        messages.appendChild(div);
        messages.scrollTop = messages.scrollHeight;
    }

    function appendAssistantBubble() {
        const div = document.createElement("div");
        div.className = "flex flex-col items-start";
        div.innerHTML =
            '<div class="max-w-[80%] rounded-lg px-4 py-3 bg-gray-800 text-gray-100"><p class="whitespace-pre-wrap"></p></div>';
        currentContentEl = div.querySelector("p");
        messages.appendChild(div);
        currentAssistantDiv = div;
        messages.scrollTop = messages.scrollHeight;
    }

    function appendError(text) {
        const div = document.createElement("div");
        div.className = "flex flex-col items-start";
        div.innerHTML =
            '<div class="max-w-[80%] rounded-lg px-4 py-3 bg-red-900 text-red-200"><p class="whitespace-pre-wrap"></p></div>';
        div.querySelector("p").textContent = "Error: " + text;
        messages.appendChild(div);
    }

    function resetAssistantState() {
        currentAssistantDiv = null;
        currentContentEl = null;
    }

    function disableInput() {
        input.disabled = true;
        sendBtn.disabled = true;
        sendBtn.classList.add("opacity-50", "cursor-not-allowed");
    }

    function enableInput() {
        input.disabled = false;
        sendBtn.disabled = false;
        sendBtn.classList.remove("opacity-50", "cursor-not-allowed");
        input.focus();
    }

    form.addEventListener("submit", function (e) {
        e.preventDefault();
        const text = input.value.trim();
        if (!text || !ws || ws.readyState !== WebSocket.OPEN) return;

        appendUserBubble(text);
        disableInput();
        ws.send(JSON.stringify({ message: text }));
        input.value = "";
    });

    connect();
})();
